mapper.select:

WITH RECURSIVE path AS (
    SELECT from_member_id, to_member_id, relation_type,
           ARRAY[from_member_id] AS visited,
           ARRAY[from_member_id::TEXT || '->' || to_member_id::TEXT] AS path_edges
    FROM relations
    WHERE family_id = #{familyId}
      AND from_member_id = #{memberAId}
    UNION ALL
    SELECT r.from_member_id, r.to_member_id, r.relation_type,
           p.visited || r.from_member_id,
           p.path_edges || (r.from_member_id::TEXT || '->' || r.to_member_id::TEXT)
    FROM relations r
    JOIN path p ON r.from_member_id = p.to_member_id
    WHERE r.family_id = #{familyId}
      AND NOT (r.from_member_id = ANY(p.visited))
      AND array_length(p.visited, 1) < 20
)
SELECT from_member_id, to_member_id, relation_type, path_edges
FROM path WHERE to_member_id = #{memberBId}
ORDER BY array_length(path_edges, 1) LIMIT 1;
